import React, { useState, useRef, useEffect } from "react";

function Attendance() {
  const videoRef = useRef(null);
  const [step, setStep] = useState("idle");
  const [message, setMessage] = useState("");
  const [attendanceLog, setAttendanceLog] = useState([]);
  const [stream, setStream] = useState(null);
  const [progress, setProgress] = useState(0);

  const student = JSON.parse(localStorage.getItem("student")) || { name: "Student", id: "N/A" };

  useEffect(() => {
    fetchAttendance();
    return () => stopCamera();
  }, []);

  useEffect(() => {
    if (stream && videoRef.current) {
      videoRef.current.srcObject = stream;
    }
  }, [stream]);

  const fetchAttendance = async () => {
    try {
      const res = await fetch("http://localhost:5000/attendance/" + student.id);
      const data = await res.json();
      setAttendanceLog(data);
    } catch (err) {
      console.log("Could not fetch attendance");
    }
  };

  const stopCamera = () => {
    if (stream) {
      stream.getTracks().forEach((track) => track.stop());
      setStream(null);
    }
  };

  const startCamera = async () => {
    try {
      const mediaStream = await navigator.mediaDevices.getUserMedia({
        video: true,
      });
      setStream(mediaStream);
      setStep("scanning");
      setMessage("👁️ Please look directly at the camera and click Scan Iris");
    } catch (err) {
      console.error("Camera error:", err);
      setStep("error");
      setMessage("❌ Camera error: " + err.message);
    }
  };

  const scanIris = () => {
    setStep("processing");
    setProgress(0);

    let prog = 0;
    const messages = [
      "🔍 Scanning iris pattern...",
      "🔍 Detecting eye structure...",
      "🔍 Matching iris data...",
      "✅ Iris matched! Marking attendance...",
    ];

    const interval = setInterval(() => {
      prog += 10;
      setProgress(prog);
      if (prog === 20) setMessage(messages[0]);
      if (prog === 50) setMessage(messages[1]);
      if (prog === 70) setMessage(messages[2]);
      if (prog === 90) setMessage(messages[3]);
      if (prog >= 100) {
        clearInterval(interval);
        markAttendance();
      }
    }, 300);
  };

  const markAttendance = async () => {
    stopCamera();
    const now = new Date();
    const record = {
      studentId: student.id,
      studentName: student.name,
      date: now.toLocaleDateString("en-IN"),
      time: now.toLocaleTimeString("en-IN"),
      status: "Present",
      method: "Iris Scan",
    };

    try {
      await fetch("http://localhost:5000/attendance", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(record),
      });
    } catch (err) {
      console.log("Saved offline");
    }

    setStep("done");
    setMessage("✅ Attendance marked successfully via Iris Scan!");
    setAttendanceLog((prev) => [record, ...prev]);
  };

  const reset = () => {
    stopCamera();
    setStep("idle");
    setMessage("");
    setProgress(0);
  };

  const today = new Date().toLocaleDateString("en-IN");
  const alreadyMarked = attendanceLog.some(
    (r) => r.date === today && r.studentId === student.id
  );

  return (
    <div className="content">
      <h3>👁️ Iris Scan Attendance</h3>
      <p style={{ color: "#555", marginTop: "5px" }}>
        Student: <strong>{student.name}</strong> | ID: <strong>{student.id}</strong>
      </p>

      {/* Already marked */}
      {alreadyMarked && step === "idle" && (
        <div style={styles.successBox}>
          ✅ Attendance already marked for today ({today})
        </div>
      )}

      {/* Idle */}
      {step === "idle" && !alreadyMarked && (
        <div style={{ marginTop: "20px", textAlign: "center" }}>
          <div style={{ fontSize: "80px", marginBottom: "15px" }}>👁️</div>
          <p style={{ color: "#555", marginBottom: "20px" }}>
            Click below to open your camera and mark attendance
          </p>
          <button style={styles.scanBtn} onClick={startCamera}>
            📷 Start Iris Scan
          </button>
        </div>
      )}

      {/* Camera scanning */}
      {step === "scanning" && (
        <div style={{ marginTop: "20px", textAlign: "center" }}>
          <div style={styles.cameraWrapper}>
            <video
              ref={videoRef}
              autoPlay
              playsInline
              muted
              style={styles.video}
            />
            <div style={styles.irisOverlay}>
              <div style={styles.irisRing} />
              <div style={styles.irisRingInner} />
            </div>
          </div>
          <p style={{ marginTop: "12px", fontWeight: "bold", color: "#007bff" }}>
            {message}
          </p>
          <div style={{ marginTop: "15px" }}>
            <button style={styles.scanBtn} onClick={scanIris}>
              👁️ Capture & Scan Iris
            </button>
            <button style={styles.cancelBtn} onClick={reset}>
              Cancel
            </button>
          </div>
        </div>
      )}

      {/* Processing */}
      {step === "processing" && (
        <div style={{ marginTop: "20px", textAlign: "center" }}>
          <div style={{ fontSize: "60px", marginBottom: "10px" }}>🔍</div>
          <div style={styles.progressBar}>
            <div style={{ ...styles.progressFill, width: progress + "%" }} />
          </div>
          <p style={{ marginTop: "15px", fontWeight: "bold", color: "#007bff" }}>
            {message}
          </p>
        </div>
      )}

      {/* Done */}
      {step === "done" && (
        <div style={{ marginTop: "20px", textAlign: "center" }}>
          <div style={{ fontSize: "60px", marginBottom: "10px" }}>✅</div>
          <div style={styles.successBox}>{message}</div>
          <button style={styles.scanBtn} onClick={reset}>
            Scan Again
          </button>
        </div>
      )}

      {/* Error */}
      {step === "error" && (
        <div style={{ marginTop: "20px", textAlign: "center" }}>
          <div style={styles.errorBox}>{message}</div>
          <button style={styles.scanBtn} onClick={reset}>
            Try Again
          </button>
        </div>
      )}

      {/* Attendance Log */}
      <div style={{ marginTop: "30px" }}>
        <h4>📋 Your Attendance Record</h4>
        {attendanceLog.length === 0 ? (
          <p style={{ color: "#888", marginTop: "10px" }}>No attendance records yet.</p>
        ) : (
          <table className="timetable" style={{ marginTop: "10px" }}>
            <thead>
              <tr>
                <th>Date</th>
                <th>Time</th>
                <th>Status</th>
                <th>Method</th>
              </tr>
            </thead>
            <tbody>
              {attendanceLog.map((r, i) => (
                <tr key={i}>
                  <td>{r.date}</td>
                  <td>{r.time}</td>
                  <td style={{ color: "green", fontWeight: "bold" }}>{r.status}</td>
                  <td>{r.method}</td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>

      <style>{`
        @keyframes pulse {
          0% { transform: translate(-50%, -50%) scale(1); opacity: 1; }
          50% { transform: translate(-50%, -50%) scale(1.1); opacity: 0.6; }
          100% { transform: translate(-50%, -50%) scale(1); opacity: 1; }
        }
      `}</style>
    </div>
  );
}

